function makeReceipt(o) {
  var st = "*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Courier New',monospace;font-size:14px;width:80mm;padding:6mm}.c{text-align:center}.hr{border:none;border-top:1px dashed #aaa;margin:7px 0}.row{display:flex;justify-content:space-between;margin:4px 0}.b{font-weight:700}@media print{@page{margin:0;size:80mm auto}}";
  var rows = o.items.map(function(i) { return "<div class=\"row\"><span style=\"flex:1\">" + i.name + (i.spice?" ("+i.spice+")":"") + "</span><span>x" + i.qty + " $" + (i.price*i.qty).toFixed(2) + "</span></div>"; }).join("");
  var sc = "<scr"+"ipt>window.onload=function(){window.print();setTimeout(function(){window.close();},700);}</scr"+"ipt>";
  return "<!DOCTYPE html><html><head><meta charset=\"utf-8\"><style>" + st + "</style></head><body>"
    + "<div class=\"c\"><b style=\"font-size:20px;letter-spacing:4px\">SEOUL JIB</b><br><small>270 St Asaph St, Christchurch</small></div>"
    + "<hr class=\"hr\"><div class=\"row\"><b>Table " + o.table + "</b><span>" + o.time + "</span></div><hr class=\"hr\">"
    + rows + (o.note?"<div style=\"background:#f5f5f5;padding:5px;margin-top:5px\">"+o.note+"</div>":"")
    + "<hr class=\"hr\"><div class=\"row b\" style=\"font-size:16px\"><span>TOTAL</span><span>$"+o.total.toFixed(2)+"</span></div>"
    + "<hr class=\"hr\"><div class=\"c\" style=\"font-size:11px;color:#888;margin-top:8px\">Thank you!</div>" + sc + "</body></html>";
}

