// ESC/POS helpers
function escPos(items, table, time, total, note) {
  var ESC=0x1B, GS=0x1D;
  var bytes=[];
  function txt(s) { for(var i=0;i<s.length;i++) bytes.push(s.charCodeAt(i)); }
  function cmd() { for(var i=0;i<arguments.length;i++) bytes.push(arguments[i]); }
  // Init
  cmd(ESC,0x40);
  // Center + double size
  cmd(ESC,0x61,1); cmd(GS,0x21,0x11);
  txt("SEOUL JIB\n");
  // Normal size
  cmd(GS,0x21,0x00); cmd(ESC,0x61,1);
  txt("270 St Asaph St, Christchurch\n");
  txt("--------------------------------\n");
  // Left align
  cmd(ESC,0x61,0);
  txt("Table: "+table+"\n");
  txt("Time:  "+time+"\n");
  txt("--------------------------------\n");
  items.forEach(function(i) {
    var line=(i.name+(i.spice?" ("+i.spice+")":"")).padEnd(20).slice(0,20);
    var qty="x"+i.qty;
    var price="$"+(i.price*i.qty).toFixed(2);
    txt(line+" "+qty.padStart(3)+" "+price.padStart(6)+"\n");
  });
  if(note) { txt("Note: "+note+"\n"); }
  txt("--------------------------------\n");
  // Bold total
  cmd(ESC,0x45,1);
  txt("TOTAL:               $"+total.toFixed(2)+"\n");
  cmd(ESC,0x45,0);
  // Center footer
  cmd(ESC,0x61,1);
  txt("\nThank you!\n\n\n");
  // Cut
  cmd(GS,0x56,0x41,0x00);
  return new Uint8Array(bytes);
}

// Cloudinary upload
var CLOUDINARY_CLOUD = "dm20nouu3";
var CLOUDINARY_PRESET = "dmjtsh8s";

async function uploadToCloudinary(base64DataUrl) {
  try {
    var formData = new FormData();
    // Convert base64 to blob
    var arr = base64DataUrl.split(',');
    var mime = arr[0].match(/:(.*?);/)[1];
    var bstr = atob(arr[1]);
    var n = bstr.length;
    var u8arr = new Uint8Array(n);
    while(n--) u8arr[n] = bstr.charCodeAt(n);
    var blob = new Blob([u8arr], {type: mime});
    formData.append('file', blob);
    formData.append('upload_preset', CLOUDINARY_PRESET);
    var res = await fetch('https://api.cloudinary.com/v1_1/'+CLOUDINARY_CLOUD+'/image/upload', {
      method: 'POST',
      body: formData
    });
    var data = await res.json();
    return data.secure_url;
  } catch(e) {
    console.error('Cloudinary upload failed:', e);
    return null;
  }
}

